import React from "react"
import { useSelector } from "react-redux"
import { selectSvgTextSize } from "../selectors"
import { splitTextInLines } from "../utils"

export enum VerticalAlign {
    MIDDLE,
    BOTTOM,
}

interface Props {
    text: string
    containerWidth: number
    containerHeight: number
    verticalAlign?: VerticalAlign
    verticalAlignPadding?: number
    xPadding?: number
    lineHeightRatio?: number
}

const SvgTextWrapped = ({
    text,
    containerWidth,
    containerHeight,
    xPadding = 0,
    lineHeightRatio = 1,
    verticalAlign = VerticalAlign.MIDDLE,
    verticalAlignPadding = 0,
    ...props
}: Props) => {
    const { charWidth, lineHeight } = useSelector(selectSvgTextSize)
    const lines = splitTextInLines(text, charWidth, containerWidth)
    const finalLineHeight = lineHeight * lineHeightRatio
    const tspans = lines.map((line) => (
        <tspan x={xPadding} dy={finalLineHeight} key={line}>
            {line}
        </tspan>
    ))

    let textY: number = 0
    if (verticalAlign === VerticalAlign.MIDDLE) {
        textY =
            containerHeight / 2 -
            (lines.length * finalLineHeight + lineHeight) / 2
    } else {
        textY =
            containerHeight -
            verticalAlignPadding -
            xPadding -
            lines.length * finalLineHeight
    }

    if (textY < 0) {
        console.error(`text not fitting in height`)
    }

    return (
        <text y={textY} {...props}>
            {tspans}
        </text>
    )
}

export default React.memo(SvgTextWrapped)
