import React from "react"
import { useSelector } from "react-redux"
import { RootState } from "../store"
import { memoizedSelectTileIdsInView } from "../selectors"
import TileHexagon from "./TileHexagon"

const HiveTiles = () => {
    const tileIdsInView = useSelector((state: RootState) =>
        memoizedSelectTileIdsInView(state)
    )
    const tileElems = tileIdsInView.map((tileId) => (
        <TileHexagon tileId={tileId} key={tileId} />
    ))
    return <React.Fragment>{tileElems}</React.Fragment>
}

export default React.memo(HiveTiles)
