import React from "react"
import { TileId, TileType } from "../../models"
import { useSelector, useDispatch } from "react-redux"
import TilePagePortal from "../TilePagePortal"
import TilePage from "../TilePage"
import { RootState } from "../../store"
import {
    selectTileFromId,
    selectClickedTileId,
    selectZoomedTileId,
} from "../../selectors"
import TileHexagonNormal from "./TileHexagonNormal"
import TileHexagonChapter from "./TileHexagonChapter"
import { useRequestZoomToTile } from "../../hooks"
import { clickedTileStart, clickedTileEnd } from "../../store/clickedTile"

interface Props {
    tileId: TileId
}

const TileHexagon = ({ tileId }: Props) => {
    const dispatch = useDispatch()
    const tile = useSelector((state: RootState) =>
        selectTileFromId(state, tileId)
    )
    if (!tile) {
        throw new Error(`unknown tile id ${tileId}`)
    }

    const currentZoomedTileId = useSelector(selectZoomedTileId)
    const clickedTileId = useSelector(selectClickedTileId)
    const [zoomToTileEffect] = useRequestZoomToTile(tileId)

    const _onClickStart = () => dispatch(clickedTileStart(tileId))
    const _onClickEnd = () => {
        dispatch(clickedTileEnd())
        if (clickedTileId === tileId) {
            zoomToTileEffect()
        }
    }

    let hexagonContentElem: JSX.Element | null = null
    if (tile.type === TileType.tile) {
        hexagonContentElem = <TileHexagonNormal tile={tile} />
    } else if (tile.type === TileType.chapter) {
        hexagonContentElem = <TileHexagonChapter tile={tile} />
    } else {
        throw new Error(`invalid tile type ${tile.type}`)
    }

    let tilePageElem: JSX.Element | null = null
    if (currentZoomedTileId === tileId) {
        tilePageElem = (
            <TilePagePortal>
                <TilePage tileId={tileId} />
            </TilePagePortal>
        )
    }

    return (
        <g
            transform={`translate(${tile.position.x} ${tile.position.y})`}
            onMouseDown={_onClickStart}
            onTouchStart={_onClickStart}
            onMouseUp={_onClickEnd}
            onTouchEnd={_onClickEnd}
        >
            {hexagonContentElem}
            {tilePageElem}
        </g>
    )
}

export default React.memo(TileHexagon)
