import React, { useEffect } from "react"
import SVGPanZoom from "./SvgPanZoom/SvgPanZoom"

import { useDispatch, useSelector } from "react-redux"
import { selectZoomedTileId, selectWindowDimensions } from "../selectors"
import { TILE_SIZE } from "../constants"
import HiveZoomer from "./HiveZoomer"
import { DRAG } from "./SvgPanZoom/internal-reducer/drag"
import { WHEEL } from "./SvgPanZoom/internal-reducer/wheel"
import { PINCH } from "./SvgPanZoom/internal-reducer/pinch"
import {
    ActionTypes as InternalActionTypes,
    RootState as SvgPanZoomRootState,
} from "./SvgPanZoom/internal-reducer"
import { updatePanning } from "./SvgPanZoom/transform/panning"
import { zoomToViewerPoint } from "./SvgPanZoom/transform/zooming"
import { getScale } from "./SvgPanZoom/utils/math"
import { RootState } from "../store"
import { setPanZoomInternal, setTransform } from "../store/panZoom"
import TextMeasurements from "./SvgTextSizeMeasurement"
import ParallaxBackground from "./ParallaxBackground"
import { useDeviceScaledSettings } from "../hooks"

const Hive = () => {
    const dispatch = useDispatch()
    const { width, height } = useSelector(selectWindowDimensions)
    const {
        initialScale,
        initialYOffsetRatio,
        maxScale,
        minScale,
    } = useDeviceScaledSettings()

    const currentZoomedTileId = useSelector(selectZoomedTileId)
    const isZoomedToPage = currentZoomedTileId !== null

    // Center the hive, the first time we load the page, and we receive width and height.
    const shouldSetTransform: boolean = !!width && !!height
    useEffect(() => {
        dispatch(
            setTransform(
                initialScale,
                (width - TILE_SIZE * initialScale) / 2,
                (height - TILE_SIZE * initialScale) * initialYOffsetRatio
            )
        )
    }, [shouldSetTransform])

    const onStateChange = (
        newState: SvgPanZoomRootState,
        previousState: SvgPanZoomRootState
    ) => {
        dispatch(setPanZoomInternal(newState, previousState))
    }

    const internalPanZoomState = useSelector(
        (state: RootState) => state.panZoom.internal
    )
    const reducer = (
        state: SvgPanZoomRootState,
        action: InternalActionTypes
    ) => {
        if (isZoomedToPage) {
            return state
        }

        switch (action.type) {
            case DRAG:
                return updatePanning(state, action.payload.x, action.payload.y)

            case WHEEL:
            case PINCH:
                const newScale =
                    getScale(state.transformMatrix) * action.payload.scaleFactor
                if (newScale < minScale || maxScale < newScale) {
                    return state
                }
                return zoomToViewerPoint(
                    state,
                    action.payload.x,
                    action.payload.y,
                    action.payload.scaleFactor
                )

            default:
                return state
        }
    }

    return (
        <SVGPanZoom
            width={width}
            height={height}
            state={internalPanZoomState}
            onStateChange={onStateChange}
            reducer={reducer}
        >
            <ParallaxBackground />
            <TextMeasurements />
            <HiveZoomer />
        </SVGPanZoom>
    )
}

export default Hive
