import React, { useRef, useEffect } from "react"
import isDeepEqual from "lodash.isequal"
import {
    getMousePosition,
    getWheelPositionAndScale,
    getPinchPoints,
    isMultiTouch,
    getTouchPosition,
} from "./utils/events"

import internalReducer, { RootState, ActionTypes } from "./internal-reducer"
import {
    dragStartAction,
    dragAction,
    dragEndAction,
} from "./internal-reducer/drag"
import {
    pinchStartAction,
    pinchAction,
    pinchEndAction,
} from "./internal-reducer/pinch"
import { wheelAction } from "./internal-reducer/wheel"

interface Props {
    scaleFactorOnWheel?: number
    reducer: (state: RootState, action: ActionTypes) => RootState
    onStateChange: (newState: RootState, state: RootState) => void
    width: number
    height: number
    state: RootState
    style?: React.CSSProperties
}

const SVGPanZoom: React.FunctionComponent<Props> = ({
    scaleFactorOnWheel = 1.06,
    reducer,
    onStateChange,
    width,
    height,
    state,
    children,
    style = {},
}) => {
    let updatedState = { ...state }

    const svgRef = useRef<SVGSVGElement>(null)
    const mergedStyle = { display: "block", touchAction: "none", ...style }

    const setState = (newState: RootState) => {
        if (isDeepEqual(state, newState)) {
            return
        }
        onStateChange(newState, state)
    }

    useEffect(() => {
        // Make sure that we stop dragging when mouse is released outside the element
        const windowMouseUp = (event: MouseEvent) => {
            updatedState = internalReducer(updatedState, dragEndAction())
            setState(updatedState)
        }
        window.addEventListener("mouseup", windowMouseUp)

        // To disables the bounce effect in ios Safari
        // ref : https://stackoverflow.com/questions/7768269/ipad-safari-disable-scrolling-and-bounce-effect
        const svgTouchMove = (ev: TouchEvent) => ev.preventDefault()
        if (svgRef.current) {
            svgRef.current.addEventListener("touchmove", svgTouchMove, {
                passive: false,
            })
        }

        return () => {
            if (svgRef.current) {
                svgRef.current.removeEventListener("touchmove", svgTouchMove)
            }
            window.removeEventListener("mouseup", windowMouseUp)
        }
    }, [state])

    return (
        <svg
            ref={svgRef}
            width={width}
            height={height}
            style={mergedStyle}
            onMouseDown={(event) => {
                const { x, y } = getMousePosition(event, svgRef.current!)
                updatedState = internalReducer(
                    updatedState,
                    dragStartAction(x, y)
                )
                // event.preventDefault()
                setState(updatedState)
            }}
            onTouchStart={(event) => {
                if (isMultiTouch(event)) {
                    const [
                        viewerPoint,
                        initialPinchPointDistance,
                    ] = getPinchPoints(event, svgRef.current!)
                    const scaleFactor = 1
                    updatedState = internalReducer(
                        updatedState,
                        pinchStartAction(initialPinchPointDistance)
                    )
                    updatedState = reducer(
                        updatedState,
                        pinchAction(
                            viewerPoint.x,
                            viewerPoint.y,
                            scaleFactor,
                            initialPinchPointDistance
                        )
                    )
                    updatedState = internalReducer(
                        updatedState,
                        pinchAction(
                            viewerPoint.x,
                            viewerPoint.y,
                            scaleFactor,
                            initialPinchPointDistance
                        )
                    )
                } else {
                    const { x, y } = getTouchPosition(event, svgRef.current!)
                    updatedState = internalReducer(
                        updatedState,
                        dragStartAction(x, y)
                    )
                }

                // event.stopPropagation()
                // event.preventDefault()
                setState(updatedState)
            }}
            onMouseMove={(event) => {
                if (updatedState.drag.dragging) {
                    const { x, y } = getMousePosition(event, svgRef.current!)
                    updatedState = reducer(updatedState, dragAction(x, y))
                    updatedState = internalReducer(
                        updatedState,
                        dragAction(x, y)
                    )
                    // event.preventDefault();
                    setState(updatedState)
                }
            }}
            onTouchMove={(event) => {
                if (isMultiTouch(event)) {
                    if (updatedState.pinch.pinching) {
                        const [
                            viewerPoint,
                            newPinchPointDistance,
                        ] = getPinchPoints(event, svgRef.current!)
                        const scaleFactor =
                            newPinchPointDistance /
                            updatedState.pinch.pinchPointDistance!
                        updatedState = reducer(
                            updatedState,
                            pinchAction(
                                viewerPoint.x,
                                viewerPoint.y,
                                scaleFactor,
                                newPinchPointDistance
                            )
                        )
                        updatedState = internalReducer(
                            updatedState,
                            pinchAction(
                                viewerPoint.x,
                                viewerPoint.y,
                                scaleFactor,
                                newPinchPointDistance
                            )
                        )
                    }
                } else {
                    if (updatedState.drag.dragging) {
                        const { x, y } = getTouchPosition(
                            event,
                            svgRef.current!
                        )
                        updatedState = reducer(updatedState, dragAction(x, y))
                        updatedState = internalReducer(
                            updatedState,
                            dragAction(x, y)
                        )
                    }
                }

                // event.stopPropagation();
                // event.preventDefault();
                setState(updatedState)
            }}
            onWheel={(event) => {
                const [viewerPoint, scaleFactor] = getWheelPositionAndScale(
                    scaleFactorOnWheel,
                    event,
                    svgRef.current!
                )
                updatedState = reducer(
                    updatedState,
                    wheelAction(viewerPoint.x, viewerPoint.y, scaleFactor)
                )
                // event.preventDefault();
                setState(updatedState)
            }}
            onMouseUp={(event) => {
                const { x, y } = getMousePosition(event, svgRef.current!)
                updatedState = reducer(updatedState, dragAction(x, y))
                updatedState = internalReducer(updatedState, dragAction(x, y))
                updatedState = internalReducer(updatedState, dragEndAction())
                // event.preventDefault();
                setState(updatedState)
            }}
            onTouchEnd={(event) => {
                if (!isMultiTouch(event)) {
                    if (updatedState.pinch.pinching) {
                        updatedState = internalReducer(
                            updatedState,
                            pinchEndAction()
                        )
                    } else if (updatedState.drag.dragging) {
                        const { x, y } = getTouchPosition(
                            event,
                            svgRef.current!
                        )
                        updatedState = reducer(updatedState, dragAction(x, y))
                        updatedState = internalReducer(
                            updatedState,
                            dragAction(x, y)
                        )
                        updatedState = internalReducer(
                            updatedState,
                            dragEndAction()
                        )
                    }
                    // event.stopPropagation()
                    // event.preventDefault()
                }
                setState(updatedState)
            }}
        >
            {children}
        </svg>
    )
}

export default SVGPanZoom
