import React, { useEffect } from "react"
import ReactGA from "react-ga"
import Hive from "./Hive"
import useInterval from "@rooks/use-interval"
import { incrementMetro } from "../store/metro"
import { METRO_INTERVAL, GOOGLE_ANALYTICS_ID } from "../constants"
import { useDispatch } from "react-redux"
import styled from "styled-components"
import theme from "../theme"
import { refreshWindowDimensions } from "../store/windowDimensions"

if (process.env.NODE_ENV === "production") {
    ReactGA.initialize(GOOGLE_ANALYTICS_ID)
    ReactGA.pageview(window.location.pathname)
}

export const AppContainer = styled.div`
    width: 100%;
    height: 100%;
    overflow: hidden;
    ${theme.mixins.scrollbar}
`

const App = () => {
    const dispatch = useDispatch()
    useInterval(() => dispatch(incrementMetro()), METRO_INTERVAL, true)

    useEffect(() => {
        const dispatchRefreshWindowDimensions = () =>
            dispatch(refreshWindowDimensions())
        window.addEventListener("resize", dispatchRefreshWindowDimensions)
        return () => {
            window.removeEventListener(
                "resize",
                dispatchRefreshWindowDimensions
            )
        }
    }, [dispatch])

    return (
        <AppContainer>
            <Hive />
        </AppContainer>
    )
}

export default App
