import { getSVGPoint } from "../utils/math"
import { RootState } from "../internal-reducer"
import { fromObject, translate, transform } from "transformation-matrix"
import { ViewerCoordinate } from "../types"

export const updatePanning = (
    state: RootState,
    viewerX: ViewerCoordinate,
    viewerY: ViewerCoordinate
) => {
    const { x: endX, y: endY } = state.drag

    const start = getSVGPoint(state.transformMatrix, endX || 0, endY || 0)
    const end = getSVGPoint(state.transformMatrix, viewerX, viewerY)

    const deltaX = end.x - start.x
    const deltaY = end.y - start.y

    const matrix = transform(
        fromObject(state.transformMatrix),
        translate(deltaX, deltaY)
    )

    return {
        ...state,
        transformMatrix: matrix,
    }
}
