import { fromObject, scale, transform, translate } from "transformation-matrix"
import { RootState } from "../internal-reducer"
import { ViewerCoordinate, SvgCoordinate } from "../types"
import { getSVGPoint } from "../utils/math"

export const zoomToSvgPoint = (
    state: RootState,
    svgX: SvgCoordinate,
    svgY: SvgCoordinate,
    scaleFactor: number
) => {
    const matrix = transform(
        fromObject(state.transformMatrix),
        translate(svgX, svgY),
        scale(scaleFactor, scaleFactor),
        translate(-svgX, -svgY)
    )
    return {
        ...state,
        transformMatrix: matrix,
    }
}

export const zoomToViewerPoint = (
    state: RootState,
    x: ViewerCoordinate,
    y: ViewerCoordinate,
    scaleFactor: number
) => {
    const { x: svgX, y: svgY } = getSVGPoint(state.transformMatrix, x, y)
    return zoomToSvgPoint(state, svgX, svgY, scaleFactor)
}
