import React from "react"
import HexagonClippedGroup from "./HexagonClippedGroup"
import Thumbnail from "./Thumbnail"
import { FrontendTile } from "../../models"
import styled from "styled-components"
import { TILE_SIZE } from "../../constants"
import theme from "../../theme"
import { useSelector } from "react-redux"
import SvgTextWrapped, { VerticalAlign } from "../SvgTextWrapped"
import { selectScale } from "../../selectors"
import { useDeviceScaledSettings } from "../../hooks"

const Title = styled(SvgTextWrapped)`
    ${theme.mixins.unselectable}
    fill: ${theme.colors.textLight};
    stroke: ${theme.colors.textDark};
    stroke-width: 0.5;
    text-transform: uppercase;
    font-size: ${Math.round(theme.svgFontSizes.basePx * 0.8)}px;
`

const Background = styled.rect`
    fill: ${theme.colors.tileHexagonBackground};
`

interface Props {
    tile: FrontendTile
}

const TileHexagonNormal = ({ tile }: Props) => {
    const { hexDetailsScaleThreshold } = useDeviceScaledSettings()
    const shouldShowDetails =
        useSelector(selectScale) >= hexDetailsScaleThreshold
    return (
        <React.Fragment>
            <HexagonClippedGroup>
                {/* This rectangle allows the tile to be clickable */}
                <Background width={TILE_SIZE} height={TILE_SIZE} />
                <Thumbnail urls={tile.thumbnails} />
            </HexagonClippedGroup>
            {shouldShowDetails ? (
                <Title
                    text={tile.title}
                    containerHeight={TILE_SIZE}
                    containerWidth={TILE_SIZE}
                    lineHeightRatio={0.7}
                    xPadding={theme.hexagonTextXPadding}
                    verticalAlign={VerticalAlign.BOTTOM}
                    verticalAlignPadding={TILE_SIZE / 4}
                />
            ) : null}
        </React.Fragment>
    )
}

export default TileHexagonNormal
