import { ViewerCoordinate } from "../types"

export const WHEEL = "WHEEL"

interface WheelAction {
    type: typeof WHEEL
    payload: {
        x: ViewerCoordinate
        y: ViewerCoordinate
        scaleFactor: number
    }
}

export type WheelActionTypes = WheelAction

export const wheelAction = (
    x: ViewerCoordinate,
    y: ViewerCoordinate,
    scaleFactor: number
): WheelActionTypes => {
    return {
        type: WHEEL,
        payload: { x, y, scaleFactor },
    }
}
