import React from "react"
import HexagonClippedGroup from "./HexagonClippedGroup"
import { FrontendTile } from "../../models"
import styled from "styled-components"
import SvgTextWrapped from "../SvgTextWrapped"
import { TILE_SIZE, SITE_TITLE } from "../../constants"
import theme from "../../theme"
import SvgTextCentered from "../SvgTextCentered"
import { useDeviceScaledSettings } from "../../hooks"

const hexagonTextStyle = `
    fill: ${theme.colors.textLight};
    font-weight: bold;
    text-transform: uppercase;
    letter-spacing: 0.25rem;
    ${theme.mixins.unselectable}
`

const ChapterRect = styled.rect`
    fill: ${theme.colors.tileHexagonBackground};
`

const Title = styled(SvgTextWrapped)`
    ${hexagonTextStyle}
    font-size: ${Math.round(theme.svgFontSizes.basePx)}px;
`

interface TitleIntroductionProps {
    fontSizeRatio: number
}

const TitleIntroduction = styled(SvgTextCentered)<TitleIntroductionProps>`
    ${hexagonTextStyle}
    font-size: ${(props) =>
        Math.round(props.fontSizeRatio * theme.svgFontSizes.basePx)}px;
    fill: ${theme.colors.textMainTitle};
    stroke: ${theme.colors.textMainTitle};
    stroke-width: ${(props) =>
        Math.round((props.fontSizeRatio * theme.svgFontSizes.basePx) / 9)}px;
`

interface Props {
    tile: FrontendTile
}

const TileHexagonChapter = ({ tile }: Props) => {
    let titleElem: JSX.Element
    const { titleFontSizeRatio } = useDeviceScaledSettings()
    if (tile.id === "Introduction") {
        titleElem = (
            <TitleIntroduction
                text={SITE_TITLE}
                containerWidth={TILE_SIZE}
                containerHeight={TILE_SIZE}
                fontSizeRatio={titleFontSizeRatio}
            />
        )
    } else {
        titleElem = (
            <Title
                text={tile.id}
                containerWidth={TILE_SIZE / 2}
                containerHeight={TILE_SIZE}
                xPadding={theme.hexagonTextXPadding}
                lineHeightRatio={1.2}
            />
        )
    }
    return (
        <React.Fragment>
            <HexagonClippedGroup>
                <ChapterRect width={TILE_SIZE} height={TILE_SIZE} />
            </HexagonClippedGroup>
            {titleElem}
        </React.Fragment>
    )
}

export default TileHexagonChapter
