import React from "react"
import styled from "styled-components"
import theme from "../theme"
import { useSelector } from "react-redux"
import { memoizedSelectTransform, selectWindowDimensions } from "../selectors"

// Add a little padding so the tiling overlaps perfectly
const IMG_HEIGHT = theme.images.bodyBackground.height - 10
const IMG_WIDTH = theme.images.bodyBackground.width - 10

const Image = styled.image`
    ${theme.mixins.unselectable}
    /* important so that the image doesn't get dragged when we drag around the svg */
    pointer-events: none;
`

const ParallaxBackground = () => {
    const { height, width } = useSelector(selectWindowDimensions)
    const transform = useSelector(memoizedSelectTransform)

    // calculate a tiling so that we repeat the background image as the parallax moves
    let currentY = transform.translate.y * theme.parallaxRatio
    const yValues: Array<number> = []
    while (currentY > 0) {
        currentY -= IMG_HEIGHT
    }
    while (currentY < height) {
        yValues.push(currentY)
        currentY += IMG_HEIGHT
    }

    let currentX = transform.translate.x * theme.parallaxRatio
    const xValues: Array<number> = []
    while (currentX > 0) {
        currentX -= IMG_WIDTH
    }
    while (currentX < width) {
        xValues.push(currentX)
        currentX += IMG_WIDTH
    }

    const imageElems: Array<JSX.Element> = []
    for (let col = 0; col < xValues.length; col++) {
        for (let row = 0; row < yValues.length; row++) {
            imageElems.push(
                <Image
                    key={`${row}:${col}`}
                    x={xValues[col]}
                    y={yValues[row]}
                    width={IMG_WIDTH + 10}
                    height={IMG_HEIGHT + 10}
                    href={theme.images.bodyBackground.url}
                    xlinkHref={theme.images.bodyBackground.url}
                />
            )
        }
    }

    return <g>{imageElems}</g>
}

export default React.memo(ParallaxBackground)
