import React from "react"
import { useSelector } from "react-redux"
import { selectSvgTextSize } from "../selectors"
import styled from "styled-components"

const CenteredText = styled.text`
    text-anchor: middle;
`

interface Props {
    text: string
    containerWidth: number
    containerHeight: number
    fontSizeRatio?: number
}

const SvgTextCentered = ({
    text,
    containerWidth,
    containerHeight,
    fontSizeRatio = 1,
    ...props
}: Props) => {
    const { lineHeight } = useSelector(selectSvgTextSize)
    // +1 because we need to account for the space between lines
    const textY = containerHeight / 2 + (lineHeight * fontSizeRatio) / 4
    const textX = containerWidth / 2
    if (textY < 0) {
        console.error(`text not fitting in height`)
    }

    return (
        <CenteredText y={textY} x={textX} {...props}>
            {text}
        </CenteredText>
    )
}

export default React.memo(SvgTextCentered)
