import React from "react"
import { TILE_SIZE } from "../../constants"
import { useSelector } from "react-redux"
import { RootState } from "../../store"
import styled from "styled-components"

// Pointer events none, to avoid browser thinking to you're trying to drag/drop an image
const ImageNoPointerEvents = styled.image`
    pointer-events: none;
`

interface Props {
    urls: Array<string>
}

const Thumbnail = ({ urls }: Props) => {
    const url = useSelector(
        (state: RootState) => urls[state.metro % urls.length]
    )
    return (
        <ImageNoPointerEvents
            width={TILE_SIZE}
            height={TILE_SIZE}
            href={url}
            xlinkHref={url}
        />
    )
}

export default Thumbnail
