export const INCREMENT_METRO = "INCREMENT_METRO"

interface IncrementMetro {
    type: typeof INCREMENT_METRO
}

export type MetroActionTypes = IncrementMetro

export const incrementMetro = (): MetroActionTypes => {
    return {
        type: INCREMENT_METRO,
    }
}

export type MetroState = number

const initialState: MetroState = 0

export function metroReducer(
    state = initialState,
    action: MetroActionTypes
): MetroState {
    switch (action.type) {
        case INCREMENT_METRO:
            return state + 1
        default:
            return state
    }
}
